public String toHexspeak(String num) {
    long n = Long.parseLong(num);
    StringBuilder hex = new StringBuilder();
    while (n != 0) {
        int rem = (int)(n % 16);
        if (rem == 1) hex.insert(0, 'I');
        else if (rem == 0) hex.insert(0, 'O');
        else if (rem > 9) hex.insert(0, (char)(rem - 10 + 'A'));
        else return "ERROR";
        n /= 16;
    }
    return hex.toString();
}
